noteContentFormat:
{% set question = selector:.QuestionHeader-title|first ?? title|replace:" - 知乎":"" %}
{% set answer_author = selector:.AnswerItem[itemprop="mainEntityOfPage"] .AuthorInfo .UserLink-link|last ?? schema:author.name ?? author %}
{% set author_url = selector:.AnswerItem[itemprop="mainEntityOfPage"] .AuthorInfo .UserLink-link?href|last %}
{% set published_at = selector:.AnswerItem[itemprop="mainEntityOfPage"] meta[itemprop="dateCreated"]?content ?? published %}
{% set modified_at = selector:.AnswerItem[itemprop="mainEntityOfPage"] meta[itemprop="dateModified"]?content ?? published_at %}
{% set upvotes = selector:.AnswerItem[itemprop="mainEntityOfPage"] [itemprop="upvoteCount"]?content %}
{% set comments = selector:.AnswerItem[itemprop="mainEntityOfPage"] meta[itemprop="commentCount"]?content %}
# {{question}}

> [!info] 知乎回答
> 作者: {% if author_url %}[{{answer_author}}](https:{{author_url}}){% else %}{{answer_author}}{% endif %}
> 原文: [{{url}}]({{url}})
> 发布时间: {{published_at|date:"YYYY-MM-DD HH:mm"}}
> 更新时间: {{modified_at|date:"YYYY-MM-DD HH:mm"}}
{% if upvotes or comments %}> 赞同: {{upvotes ?? "0"}} | 评论: {{comments ?? "0"}}{% endif %}

## 回答正文

{{selectorHtml:.AnswerItem[itemprop="mainEntityOfPage"] .RichContent-inner|markdown}}

{% if highlights %}
## 高亮

{{highlights|fragment_link:"回到原文"|join:"\n\n"}}
{% endif %}
